use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

#[derive(Debug)]
pub struct Inventory {
    items: Mutex<HashMap<String, usize>>,
}

impl Inventory {
    pub fn new(initial: HashMap<String, usize>) -> Self {
        Self {
            items: Mutex::new(initial),
        }
    }

    pub fn check_stock(&self, sku: &str) -> usize {
        let items = self.items.lock().unwrap();
        *items.get(sku).unwrap_or(&0)
    }

    pub fn decrement(&self, sku: &str, amount: usize) -> bool {
        let mut items = self.items.lock().unwrap();
        match items.get_mut(sku) {
            Some(stock) if *stock >= amount => {
                *stock -= amount;
                true
            }
            _ => false,
        }
    }
}

pub fn concurrent_inventory_updates() {
    let mut initial = HashMap::new();
    initial.insert("widget".to_string(), 100);
    initial.insert("gadget".to_string(), 50);

    let inventory = Arc::new(Inventory::new(initial));
    let mut handles = Vec::new();

    for _ in 0..10 {
        let inv = Arc::clone(&inventory);
        handles.push(thread::spawn(move || {
            let current = inv.check_stock("widget");
            if current > 0 {
                let _ = inv.decrement("widget", 1);
            }
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }
}